&lt;h4 id=&#34;8080&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#8080&#34;&gt;#&lt;/a&gt; 8080&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;jenkins   一个持续集成的工具&lt;/p&gt;
&lt;/blockquote&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;jenkins&lt;/th&gt;
